import React, { useState, useRef, useEffect } from "react";
import "./GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. How are you feeling today?",
    },
  ]);

  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  // ✅ Auto-scroll (messages go UP, input stays visible)
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    setMessages((prev) => [...prev, userMessage]);
    setInput("");

    // Simulate AI thinking delay
    setTimeout(() => {
      const botMessage = {
        sender: "bot",
        text: generateBotReply(input),
      };

      setMessages((prev) => [...prev, botMessage]);
    }, 800);
  };

  const generateBotReply = (msg) => {
    const text = msg.toLowerCase();

    if (text.includes("sad") || text.includes("low"))
      return "I’m really sorry you’re feeling this way 💜 Want to tell me what’s been bothering you?";

    if (text.includes("stress") || text.includes("pressure"))
      return "That sounds overwhelming 😔 Let’s take it one step at a time. What’s causing the stress?";

    if (text.includes("lonely"))
      return "Feeling lonely can hurt deeply 💙 I’m here with you. You don’t have to go through this alone.";

    if (text.includes("anxious") || text.includes("anxiety"))
      return "Anxiety can feel scary, but you’re safe right now 🌿 Try taking a slow breath with me.";

    if (text.includes("happy"))
      return "That’s really nice to hear 😊 What made you feel happy today?";

    return "I’m listening 💜 Take your time and tell me more.";
  };

  return (
    <div className="chat-container">
      <h2 className="chat-title">General Chat</h2>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div key={index} className={`chat-message ${msg.sender}`}>
            {msg.text}
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
